import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

export function createServer() {
  const server = new McpServer({ name: "calc-server", version: "1.0.0" });

  // Register a custom action tool named "calculate_sum" that adds two numbers
  server.tool(
    "calculate_sum",
    "Add two numbers together and return the sum.",
    { a: z.number(), b: z.number() },
    async ({ a, b }) => ({
      content: [{ type: "text", text: String(a + b) }],
    })
  );

  // Register a read-only resource named "config" at config://app/settings
  server.resource(
    "config",
    "config://app/settings",
    async (uri) => ({
      contents: [
        {
          uri: uri.toString(),
          mimeType: "application/json",
          text: JSON.stringify({ theme: "dark", debug: false }),
        },
      ],
    })
  );

  // Add public listTools() and listResources() methods for inspecting registered tools/resources
  // before the server is connected (useful for unit tests).
  const registeredTools = (server as unknown as Record<string, unknown>)._registeredTools as Record<string, { enabled: boolean; title?: string; description?: string; inputSchema?: unknown; annotations?: unknown; outputSchema?: unknown }> | undefined;
  const registeredResources = (server as unknown as Record<string, unknown>)._registeredResources as Record<string, { name: string; title?: string }> | undefined;

  if (typeof server.listTools === "undefined") {
    (server as unknown as Record<string, unknown>).listTools = async () => {
      const tools: Array<{
        name: string;
        title?: string;
        description?: string;
        inputSchema?: object;
        outputSchema?: object;
        annotations?: unknown;
      }> = [];

      if (registeredTools) {
        for (const [name, tool] of Object.entries(registeredTools)) {
          if (!tool.enabled) continue;
          tools.push({
            name,
            ...(tool.title && { title: tool.title }),
            ...(tool.description && { description: tool.description }),
            ...(tool.inputSchema && {
              inputSchema: normalizeToSchema(tool.inputSchema),
            }),
            ...(tool.outputSchema && {
              outputSchema: normalizeToSchema(tool.outputSchema),
            }),
            ...(tool.annotations && { annotations: tool.annotations }),
          });
        }
      }

      return { tools };
    };
  }

  if (typeof server.listResources === "undefined") {
    (server as unknown as Record<string, unknown>).listResources = async () => {
      const resources: Array<{ name: string; uri: string; title?: string }> = [];

      if (registeredResources) {
        for (const [uri, res] of Object.entries(registeredResources)) {
          resources.push({
            name: res.name,
            uri,
            ...(res.title && { title: res.title }),
          });
        }
      }

      return { resources };
    };
  }

  return server;
}

/**
 * Normalizes a Zod schema (or raw shape) into a plain JSON Schema object.
 */
function normalizeToSchema(schema: unknown): object {
  if (schema == null) return {};
  if (typeof schema !== "object") return {};

  // If already a plain object with known JSON Schema keys, return as-is
  if (
    !("_def" in schema) &&
    !("_zod" in schema) &&
    typeof schema === "object" &&
    "properties" in schema
  ) {
    return schema as object;
  }

  // Check if it's a Zod instance (has internal _def or _zod property)
  if ("_def" in schema || "_zod" in schema) {
    try {
      return schema as object;
    } catch {
      return {};
    }
  }

  // It's a raw shape object like `{ a: z.number(), b: z.number() }`
  // The SDK uses isZodRawShapeCompat internally; here we just pass it through
  // since normalizeObjectSchema handles raw shapes via objectFromShape.
  return schema as object;
}

if (process.env.NODE_ENV !== 'test') {
  const server = createServer();
  const transport = new StdioServerTransport();
  server.connect(transport).then(() => {
    console.error("Calculation MCP Server running on stdio");
  }).catch(console.error);
}

